 ('seoul-palace'),('seoul-night'),('seongsu-picnic'),('daejeon-science'),('daejeon-bread'),('daejeon-green'),
 ('family-daejeon'),('seoul-modern'),('seoul-summer'),('daejeon-autumn')) x(k))
ON CONFLICT DO NOTHING;

